import boto3
import requests
from botocore.exceptions import NoCredentialsError
from urllib.parse import urlparse

def lambda_handler(event, context):
    try:
        # Get the URL from the X-Enrich-URL header
        enrich_url = event['headers'].get('X-Enrich-URL')
        
        if not enrich_url:
            return {
                'status': 400,
                'body': 'Missing X-Enrich-URL header'
            }
        
        # Validate the URL
        try:
            result = urlparse(enrich_url)
            if not all([result.scheme, result.netloc]):
                raise ValueError('Invalid URL')
        except ValueError as e:
            return {
                'status': 400,
                'body': str(e)
            }
        
        # Make the request to fetch additional data
        try:
            response = requests.get(enrich_url, timeout=5)
            response.raise_for_status()
        except requests.RequestException as e:
            return {
                'status': 500,
                'body': str(e)
            }
        
        # Add the fetched data to the event
        event['context'] = response.json()
        
        # Forward the request to the origin
        return {
            'status': 200,
            'body': '',
            'headers': {
                'Access-Control-Allow-Origin': '*'
            },
            'isBase64Encoded': False
        }
    
    except Exception as e:
        print(f'Error: {str(e)}')
        return {
            'status': 500,
            'body': str(e)
        }

